import jsonimport refrom pathlib import Pathfrom typing import List, Dict, AnyINPUT_PATH = Path("data/procedures.json")OUTPUT_PATH = Path("data/chunks.json")TARGET_WORDS = 220OVERLAP_PARAGRAPHS = 1MIN_CHUNK_WORDS = 25def load_procedures(file_path: Path) -> List[Dict[str, Any]]:    if not file_path.exists():        raise FileNotFoundError(f"Input file not found: {file_path}")    with file_path.open("r", encoding="utf-8") as f:        data = json.load(f)    if not isinstance(data, list):        raise ValueError("Expected procedures.json to contain a list of records.")    return datadef save_chunks(chunks: List[Dict[str, Any]], output_path: Path) -> None:    output_path.parent.mkdir(parents=True, exist_ok=True)    with output_path.open("w", encoding="utf-8") as f:        json.dump(chunks, f, indent=2, ensure_ascii=False)def normalize_whitespace(text: str) -> str:    return re.sub(r"\s+", " ", text).strip()def word_count(text: str) -> int:    return len(text.split())def make_base_id(title: str) -> str:    title = title.lower().strip()    title = re.sub(r"[^a-z0-9]+", "_", title)    title = re.sub(r"_+", "_", title).strip("_")    return title or "procedure"def is_heading(paragraph: str) -> bool:    """    Heuristic: short paragraph ending with ? or looking title-like.    Works well enough for the scraped I-MED pages.    """    p = paragraph.strip()    if not p:        return False    if len(p.split()) <= 10 and (        p.endswith("?")        or p.lower() in {            "key points",            "what is an ultrasound?",            "how much will my procedure cost?",            "why would my doctor refer me for an ultrasound?",            "how do i prepare for an ultrasound?",            "what happens during an ultrasound?",            "how long does an ultrasound take?",            "what are the benefits of ultrasound?",            "who does an ultrasound?",            "what are the risks of an ultrasound?",            "are there any after effects of an ultrasound?",            "how do i get my results?",            "i need an ultrasound for suspected dvt, what do i do?",            "abdomen ultrasound",            "female pelvis ultrasound",            "renal (kidney related) ultrasound",            "early pregnancy <12 week ultrasound",            "pregnancy 17-22 week ultrasound",            "vascular (blood vessel related) ultrasound",            "interventional ultrasound",        }    ):        return True    # title-case-ish short lines    if len(p.split()) <= 8 and p[0].isupper() and not p.endswith("."):        return True    return Falsedef split_into_paragraphs(text: str) -> List[str]:    paragraphs = [normalize_whitespace(p) for p in text.split("\n\n")]    return [p for p in paragraphs if p]def split_large_section(    section_heading: str,    section_paragraphs: List[str],    target_words: int = TARGET_WORDS,    overlap_paragraphs: int = OVERLAP_PARAGRAPHS,    min_chunk_words: int = MIN_CHUNK_WORDS,) -> List[str]:    """    Split a large section into chunk-sized pieces while keeping the heading attached.    Guarantees forward progress.    """    chunks = []    start = 0    while start < len(section_paragraphs):        current_parts = [section_heading] if section_heading else []        current_words = word_count(section_heading) if section_heading else 0        end = start        # Grow chunk forward        while end < len(section_paragraphs):            para = section_paragraphs[end]            para_words = word_count(para)            if current_words == 0 or current_words + para_words <= target_words:                current_parts.append(para)                current_words += para_words                end += 1            else:                break        # If even a single paragraph is too large, force it into its own chunk        if end == start:            para = section_paragraphs[start]            current_parts.append(para)            end = start + 1        chunk_text = "\n\n".join(current_parts).strip()        if word_count(chunk_text) >= min_chunk_words:            chunks.append(chunk_text)        # Move start forward with overlap        next_start = max(start + 1, end - overlap_paragraphs)        if next_start <= start:            next_start = end        start = next_start    return chunksdef build_section_chunks(content: str) -> List[str]:    """    Group content by heading, then split only oversized sections.    """    paragraphs = split_into_paragraphs(content)    if not paragraphs:        return []    sections = []    current_heading = ""    current_body = []    for para in paragraphs:        if is_heading(para):            if current_heading or current_body:                sections.append((current_heading, current_body))            current_heading = para            current_body = []        else:            current_body.append(para)    if current_heading or current_body:        sections.append((current_heading, current_body))    chunks = []    for heading, body in sections:        combined = "\n\n".join(([heading] if heading else []) + body).strip()        if word_count(combined) <= TARGET_WORDS:            if word_count(combined) >= MIN_CHUNK_WORDS:                chunks.append(combined)        else:            chunks.extend(split_large_section(heading, body))    return chunksdef build_chunks(procedures: List[Dict[str, Any]]) -> List[Dict[str, Any]]:    all_chunks = []    for procedure in procedures:        if procedure.get("status") != "success":            continue        title = procedure.get("title", "Untitled")        url = procedure.get("url", "")        content = procedure.get("content", "").strip()        if not content:            continue        text_chunks = build_section_chunks(content)        base_id = make_base_id(title)        for idx, chunk_text in enumerate(text_chunks):            all_chunks.append({                "chunk_id": f"{base_id}_{idx}",                "title": title,                "url": url,                "text": chunk_text,                "word_count": word_count(chunk_text),            })    return all_chunksdef print_summary(chunks: List[Dict[str, Any]]) -> None:    print(f"Created {len(chunks)} chunks.")    if chunks:        avg_words = sum(c["word_count"] for c in chunks) / len(chunks)        print(f"Average words per chunk: {avg_words:.1f}")        example = chunks[0]        print("\nExample chunk:")        print(f"- chunk_id: {example['chunk_id']}")        print(f"- title: {example['title']}")        print(f"- url: {example['url']}")        print(f"- word_count: {example['word_count']}")        print(f"- preview: {example['text'][:300]}...")def main() -> None:    procedures = load_procedures(INPUT_PATH)    chunks = build_chunks(procedures)    save_chunks(chunks, OUTPUT_PATH)    print_summary(chunks)    print(f"\nSaved chunks to: {OUTPUT_PATH}")if __name__ == "__main__":    main()